import type {
    ClientLogDevicesResponse,
    CreateStoryBody,
    CreateStoryResponse,
    LogsResponse,
    LogLevel,
    PatchScrumboardBody,
    PatchStoryBody,
    ProjectDashboardData,
    ProjectGitLogResponse,
    ProjectSummaryData,
    ProjectStoriesResponse,
    ScrumboardResponse,
    StoryDraftResponse,
    StoryResponse,
} from '@motivation/shared';
import { API_URL } from '../config.js';

export class ProjectsService {
    static async fetchMotivationSummary(): Promise<ProjectSummaryData> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/summary`);
        if (!response.ok) {
            throw new Error(`Failed to fetch motivation summary: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchMotivationDashboard(): Promise<ProjectDashboardData> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation`);
        if (!response.ok) {
            throw new Error(`Failed to fetch motivation dashboard: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchMotivationStories(): Promise<ProjectStoriesResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories`);
        if (!response.ok) {
            throw new Error(`Failed to fetch motivation stories: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchMotivationGitLog(): Promise<ProjectGitLogResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/git-log`);
        if (!response.ok) {
            throw new Error(`Failed to fetch motivation git log: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchMotivationLogs(params?: { date?: string; level?: LogLevel[]; search?: string; limit?: number; offset?: number }): Promise<LogsResponse> {
        const query = new URLSearchParams();
        if (params?.date) query.set('date', params.date);
        if (params?.level?.length) query.set('level', params.level.join(','));
        if (params?.search) query.set('search', params.search);
        if (params?.limit != null) query.set('limit', String(params.limit));
        if (params?.offset != null) query.set('offset', String(params.offset));
        const qs = query.toString();
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/logs${qs ? `?${qs}` : ''}`);
        if (!response.ok) {
            throw new Error(`Failed to fetch logs: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchClientLogDevices(): Promise<ClientLogDevicesResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/client-logs/devices`);
        if (!response.ok) {
            throw new Error(`Failed to fetch client log devices: ${response.statusText}`);
        }
        return response.json();
    }

    static async fetchScrumboard(): Promise<ScrumboardResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/scrumboard`);
        if (!response.ok) throw new Error(`Failed to fetch scrumboard: ${response.statusText}`);
        return response.json();
    }

    static async patchScrumboard(body: PatchScrumboardBody): Promise<ScrumboardResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/scrumboard`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!response.ok) throw await scrumboardErrorFor(response, 'patch scrumboard');
        return response.json();
    }

    static async fetchStory(id: string): Promise<StoryResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/${encodeURIComponent(id)}`);
        if (!response.ok) throw new Error(`Failed to fetch story ${id}: ${response.statusText}`);
        return response.json();
    }

    static async createStory(body: CreateStoryBody): Promise<CreateStoryResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!response.ok) throw await scrumboardErrorFor(response, 'create story');
        return response.json();
    }

    static async draftStoryFromNotes(notes: string): Promise<StoryDraftResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/draft-from-notes`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ notes }),
        });
        if (!response.ok) throw await scrumboardErrorFor(response, 'draft story from notes');
        return response.json();
    }

    static async patchStory(id: string, body: PatchStoryBody): Promise<StoryResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/${encodeURIComponent(id)}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!response.ok) throw await scrumboardErrorFor(response, `patch story ${id}`);
        return response.json();
    }

    static async fetchClientLogs(params: {
        device: string;
        date?: string;
        level?: LogLevel[];
        search?: string;
        limit?: number;
        offset?: number;
    }): Promise<LogsResponse> {
        const query = new URLSearchParams();
        query.set('device', params.device);
        if (params.date) query.set('date', params.date);
        if (params.level?.length) query.set('level', params.level.join(','));
        if (params.search) query.set('search', params.search);
        if (params.limit != null) query.set('limit', String(params.limit));
        if (params.offset != null) query.set('offset', String(params.offset));
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/client-logs?${query.toString()}`);
        if (!response.ok) {
            throw new Error(`Failed to fetch client logs: ${response.statusText}`);
        }
        return response.json();
    }
}

/**
 * Surface server-side error details for write paths. The server returns `{ error: "..." }` for
 * 4xx/5xx; we want to render that message in the UI instead of just the bland HTTP status text.
 */
async function scrumboardErrorFor(response: Response, action: string): Promise<Error> {
    let detail = '';
    try {
        const body = await response.json() as { error?: string };
        if (body?.error) detail = `: ${body.error}`;
    } catch {
        // Swallow non-JSON error bodies — fall back to the status text.
    }
    return new Error(`Failed to ${action} (${response.status} ${response.statusText})${detail}`);
}
